from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about astronauts (or related entities) into a
    fluent English sentence.  The function groups triples by their subject and
    builds a clause for each predicate, then joins the clauses into a single
    (or a few) readable sentences.
    """
    if not triples:
        return ""

    # Helper to turn a predicate/object pair into a phrase
    def phrase(subj: str, pred: str, obj: str) -> tuple[str, bool]:
        """
        Return a phrase and a flag indicating whether the phrase is an
        attribute that can be combined with other attributes of the same subject.
        """
        obj = obj.strip().strip('"')
        p = pred.lower().replace(" ", "")
        def fmt_date(d: str) -> str:
            try:
                from datetime import datetime
                dt = datetime.strptime(d, "%Y-%m-%d")
                return dt.strftime("%B %-d, %Y")
            except Exception:
                return d

        # Attribute predicates that can be merged into a single “is …” clause
        attribute_predicates = {
            "nationality",
            "occupation",
            "status",
            "selectedbynasa",
            "timeinspace",
            "title",
            "award",
            "awards",
            "ribbonaward",
            "servedaschiefoftheastronautofficein",
        }

        # Helper to produce attribute fragments without repeating the subject
        if p == "nationality":
            low_obj = obj.lower()
            if low_obj in ("united states", "usa", "united states of america"):
                return ("an American", True)
            if low_obj.startswith("the "):
                return (f"from {obj}", True)
            return (f"from the {obj}", True)

        if p == "occupation":
            return (f"a {obj}", True)

        if p == "status":
            low = obj.lower()
            if low == "retired":
                return ("retired", True)
            return (low, True)

        if p == "selectedbynasa":
            return (f"selected by NASA in {obj}", True)

        if p == "timeinspace":
            try:
                mins = float(obj)
                hrs = int(mins // 60)
                rem = int(mins % 60)
                if hrs and rem:
                    return (f"spent {hrs} hour{'s' if hrs>1 else ''} and {rem} minute{'s' if rem!=1 else ''} in space", True)
                if hrs:
                    return (f"spent {hrs} hour{'s' if hrs>1 else ''} in space", True)
                return (f"spent {rem} minute{'s' if rem!=1 else ''} in space", True)
            except Exception:
                return (f"spent {obj} minutes in space", True)

        if p == "title":
            return (f"held the title of {obj}", True)

        if p == "award":
            return (f"received the {obj}", True)

        if p == "awards":
            return (f"received {obj} awards", True)

        if p == "ribbonaward":
            return (f"was awarded the {obj}", True)

        if p == "servedaschiefoftheastronautofficein":
            return (f"served as Chief of the Astronaut Office in {obj}", True)

        # Non‑attribute predicates – return a full clause with the subject
        if p == "birthdate":
            return (f"{subj} was born on {fmt_date(obj)}", False)
        if p == "birthplace":
            return (f"{subj} was born in {obj}", False)
        if p == "deathdate":
            return (f"{subj} died on {fmt_date(obj)}", False)
        if p == "deathplace":
            return (f"{subj} died in {obj}", False)
        if p == "mission":
            return (f"{subj} was a crew member of {obj}", False)
        if p == "operator":
            return (f"The {subj} was operated by {obj}", False)
        if p == "commander":
            return (f"{obj} was the commander of {subj}", False)
        if p == "backuppilot":
            return (f"{subj}'s backup pilot was {obj}", False)
        if p == "crewmembers":
            return (f"{obj} was a crew member of {subj}", False)
        if p == "alternativename":
            return (f"{subj} is also known as {obj}", False)
        if p == "representative":
            return (f"{obj} was the representative of {subj}", False)
        if p == "bird":
            return (f"The {obj} is the state bird of {subj}", False)
        if p == "leader":
            # Subject is a country, object is a person
            return (f"{obj} is the leader of {subj}", False)

        # Handle partsType specially: infer a location type
        if p == "partstype":
            # Simplify: treat as “is a … in …” if object mentions “in”
            if "in" in obj.lower():
                return (f"is a {obj.split('in')[0].strip().lower()}", True)
            return (f"is a {obj.lower()}", True)

        # Generic fallback
        return (f"{subj} {pred} {obj}", False)

    # Group triples by subject
    from collections import defaultdict
    groups = defaultdict(list)
    for t in triples:
        groups[t.subject].append(t)

    sentences = []
    for subj, items in groups.items():
        parts = [phrase(subj, t.predicate, t.object) for t in items]
        # Join parts with commas and a final conjunction
        if len(parts) == 1:
            sent = parts[0]
        else:
            sent = ", ".join(parts[:-1]) + ", and " + parts[-1]
        sentences.append(sent)

    # Combine subject sentences
    return " Also, ".join(sentences) + "."

# EVOLVE-BLOCK-END
